// EMERGENCY STOP CHECK
// Must be the first code node in every workflow, right after the trigger.
// Checks the EMERGENCY_STOP environment variable. If true, sends a
// notification to Discord and halts the workflow (returns empty array).
//
// Referenced in: crisis.md, n8n-workflow-specs.md
// Variable: EMERGENCY_STOP (Settings > Variables)

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  const workflowName = $workflow.name || 'Unknown Workflow';
  const timestamp = new Date().toISOString();

  const discordUrl = $env.DISCORD_WEBHOOK_URL;
  if (discordUrl) {
    try {
      await fetch(discordUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: `**EMERGENCY STOP ACTIVE** | Workflow "${workflowName}" halted at ${timestamp}. No content was published. Set EMERGENCY_STOP=false in n8n variables to resume.`
        })
      });
    } catch (e) {
      // Discord notification failed, but we still halt.
    }
  }

  return [];
}

return $input.all();

// PRE-POST EMERGENCY STOP CHECK
// Second check right before scheduling and moving items.
// Catches mid-execution activation of EMERGENCY_STOP.

const emergencyStop = $env.EMERGENCY_STOP;

if (emergencyStop === 'true' || emergencyStop === true) {
  return [];
}

return $input.all();

// Read approved queue from static data (n8n Cloud compatible)
// Queue items are stored via webhook or manual entry
const staticData = $getWorkflowStaticData('global');

if (!staticData.approved_queue) {
  staticData.approved_queue = [];
}

const items = staticData.approved_queue;

return [{ json: { items: items, count: items.length } }];

const items = $input.first().json.items;
const today = new Date().toISOString().split('T')[0];

const todaysItems = items.filter(item =>
  item.scheduled_date === today || !item.scheduled_date
);

todaysItems.sort((a, b) => (a.priority || 5) - (b.priority || 5));

if (todaysItems.length === 0) {
  return [{ json: { no_items: true, today, total_in_queue: items.length } }];
}

return [{ json: { items: todaysItems, count: todaysItems.length, today } }];

// Cadence rules from cadence.md:
// - @v0idai: max 6/day hard limit, 1-2/day target, 3hr min gap
// - Weekend: max 1/day per account
// - Never > 6 from any single account

const items = $input.first().json.items;
const today = new Date();
const isWeekend = today.getDay() === 0 || today.getDay() === 6;
const maxPerDay = parseInt($env.MAX_POSTS_PER_DAY || '6', 10);

const byAccount = {};
for (const item of items) {
  const acct = item.account || '@v0idai';
  if (!byAccount[acct]) byAccount[acct] = [];
  byAccount[acct].push(item);
}

const scheduled = [];
const deferred = [];

for (const [account, accountItems] of Object.entries(byAccount)) {
  const dailyLimit = isWeekend ? 1 : Math.min(maxPerDay, 2);
  const toPost = accountItems.slice(0, dailyLimit);
  const toDefer = accountItems.slice(dailyLimit);

  scheduled.push(...toPost.map((item, i) => ({ ...item, slot_index: i })));
  deferred.push(...toDefer.map(item => ({ ...item, deferred_reason: 'cadence_limit' })));
}

return [{
  json: {
    scheduled,
    deferred,
    is_weekend: isWeekend,
    scheduled_count: scheduled.length,
    deferred_count: deferred.length
  }
}];

// Optimal posting windows from cadence.md:
// @v0idai peak: 14:00-16:00 UTC, 20:00-22:00 UTC
const items = $input.first().json.scheduled;

const timeSlots = [
  { hour: 14, minute: 0 },
  { hour: 15, minute: 30 },
  { hour: 17, minute: 0 },
  { hour: 20, minute: 0 },
  { hour: 21, minute: 30 },
];

const today = new Date().toISOString().split('T')[0];

const withTimes = items.map((item, i) => {
  const slot = timeSlots[i % timeSlots.length];
  const scheduledTime = `${today}T${String(slot.hour).padStart(2, '0')}:${String(slot.minute).padStart(2, '0')}:00Z`;

  return {
    ...item,
    scheduled_post_at: scheduledTime,
    time_slot: `${slot.hour}:${String(slot.minute).padStart(2, '0')} UTC`
  };
});

return [{
  json: {
    items: withTimes,
    deferred: $input.first().json.deferred,
    scheduled_count: withTimes.length,
    deferred_count: $input.first().json.deferred.length
  }
}];

// DRY_RUN log: prepare schedule summary for Discord
const data = $input.first().json;

const logEntry = {
  workflow: 'content-calendar-scheduler',
  timestamp: new Date().toISOString(),
  dry_run: true,
  scheduled_items: (data.items || []).map(item => ({
    title: item.title || item.filename || 'Untitled',
    account: item.account || '@v0idai',
    type: item.type || 'x-single',
    scheduled_post_at: item.scheduled_post_at,
    time_slot: item.time_slot
  })),
  deferred_items: (data.deferred || []).map(item => ({
    title: item.title || item.filename || 'Untitled',
    reason: item.deferred_reason
  })),
  scheduled_count: data.scheduled_count || 0,
  deferred_count: data.deferred_count || 0
};

return [{ json: { status: 'schedule_logged', ...logEntry } }];

// In production: move items from approved to scheduled in static data
// and prepare for posting API calls
const staticData = $getWorkflowStaticData('global');
const items = $input.first().json.items || [];

if (!staticData.scheduled_queue) {
  staticData.scheduled_queue = [];
}

const results = [];
for (const item of items) {
  // Add to scheduled queue with posting time
  const scheduledItem = {
    ...item,
    status: 'scheduled',
    moved_at: new Date().toISOString()
  };
  staticData.scheduled_queue.push(scheduledItem);

  // Remove from approved queue
  if (staticData.approved_queue) {
    const idx = staticData.approved_queue.findIndex(
      a => (a.id && a.id === item.id) || (a.title && a.title === item.title)
    );
    if (idx !== -1) {
      staticData.approved_queue.splice(idx, 1);
    }
  }

  results.push({
    title: item.title || item.filename || 'Untitled',
    account: item.account || '@v0idai',
    scheduled_post_at: item.scheduled_post_at,
    status: 'moved_to_scheduled'
  });
}

// Clean up old scheduled items (keep last 50)
if (staticData.scheduled_queue.length > 50) {
  staticData.scheduled_queue = staticData.scheduled_queue.slice(-50);
}

return [{ json: { results, moved_count: results.length, deferred: $input.first().json.deferred, deferred_count: $input.first().json.deferred_count } }];

